import{_ as a}from"./chunks/开始注册.D2sAS_1D.js";import{_ as t}from"./chunks/填写注册信息.D9Rv_fLW.js";import{_ as i}from"./chunks/编辑资料.C8Y3jCG0.js";import{_ as o,o as r,c as e,ae as s}from"./chunks/framework.BD9pLfSD.js";const n="/assets/%E9%82%AE%E7%AE%B1%E9%AA%8C%E8%AF%81.CWSRhqNV.png",p="/assets/%E5%BF%98%E8%AE%B0%E5%AF%86%E7%A0%81.k7La7SqI.png",u="/assets/%E5%88%87%E6%8D%A2%E8%BA%AB%E4%BB%BD.BlZDbaQb.png",E=JSON.parse('{"title":"账户相关问题","description":"","frontmatter":{},"headers":[],"relativePath":"1-FAQ/1-account.md","filePath":"1-FAQ/1-account.md"}'),h={name:"1-FAQ/1-account.md"};function c(q,l,g,m,d,_){return r(),e("div",null,[...l[0]||(l[0]=[s('<h1 id="账户相关问题" tabindex="-1">账户相关问题 <a class="header-anchor" href="#账户相关问题" aria-label="Permalink to &quot;账户相关问题&quot;">​</a></h1><h2 id="注册与登录" tabindex="-1">注册与登录 <a class="header-anchor" href="#注册与登录" aria-label="Permalink to &quot;注册与登录&quot;">​</a></h2><h3 id="q1-如何注册-登录账号" tabindex="-1">Q1: 如何注册/登录账号？ <a class="header-anchor" href="#q1-如何注册-登录账号" aria-label="Permalink to &quot;Q1: 如何注册/登录账号？&quot;">​</a></h3><p><strong>A</strong>: 点击页面右上角&quot;开始&quot;按钮，点击&quot;<em>还没有账号？注册</em> &quot;：</p><p><img src="'+a+'" alt="注册页面"><em>图：CogniAND 注册/登录页面</em></p><p><strong>需要填写的信息：</strong></p><ul><li>邮箱地址（必填，用于登录）</li><li>密码（必填，至少8位）</li><li>姓名（firstName + lastName）</li><li>性别（male/female/prefer_not_to_say）</li><li>出生日期（年月日）</li></ul><p><strong>邀请码（选填）：</strong></p><ul><li>有邀请码可获得额外权限，无邀请码也可注册为普通用户</li></ul><p><img src="'+t+'" alt="注册页面"></p><p>提交后系统会发送验证邮件，用户输入验证码进行验证。 <img src="'+n+'" alt="注册页面"></p><p>详细步骤：<a href="/3-subject-manual/2-registration.html">注册流程</a></p><h3 id="q2-忘记密码怎么办" tabindex="-1">Q2: 忘记密码怎么办？ <a class="header-anchor" href="#q2-忘记密码怎么办" aria-label="Permalink to &quot;Q2: 忘记密码怎么办？&quot;">​</a></h3><p><strong>A</strong>: 在登录页面点击&quot;忘记密码&quot;链接，输入注册邮箱，系统会发送密码重置邮件，输入邮件中的验证码进行密码重置。 <img src="'+p+'" alt="忘记密码"></p><p><strong>注意事项</strong>：</p><ul><li>重置链接有效期通常为24小时</li><li>重置链接只能使用一次</li><li>建议使用强密码（包含大小写字母、数字和特殊字符）</li></ul><h3 id="q3-如何切换角色" tabindex="-1">Q3: 如何切换角色？ <a class="header-anchor" href="#q3-如何切换角色" aria-label="Permalink to &quot;Q3: 如何切换角色？&quot;">​</a></h3><p><strong>A</strong>: 登录后进入个人中心，在&quot;角色管理&quot;中选择要切换的角色即可。</p><p><img src="'+u+'" alt="注册页面"></p><p><strong>温馨提醒</strong>：</p><ul><li>注册时必须选择了多个角色</li><li>角色切换不会影响已有数据和权限</li></ul><h3 id="q4-邮箱验证失败怎么办" tabindex="-1">Q4: 邮箱验证失败怎么办？ <a class="header-anchor" href="#q4-邮箱验证失败怎么办" aria-label="Permalink to &quot;Q4: 邮箱验证失败怎么办？&quot;">​</a></h3><p><strong>A</strong>: 请检查以下几点：</p><ul><li>邮箱地址是否正确</li><li>验证码是否输入正确</li><li>如仍失败，点击&quot;重新发送验证邮件&quot;</li></ul><p><strong>常见原因</strong>：</p><ol><li>验证邮件在垃圾邮件文件夹</li><li>邮箱地址输入错误</li></ol><h2 id="个人信息管理" tabindex="-1">个人信息管理 <a class="header-anchor" href="#个人信息管理" aria-label="Permalink to &quot;个人信息管理&quot;">​</a></h2><h3 id="q5-如何修改个人信息" tabindex="-1">Q5: 如何修改个人信息？ <a class="header-anchor" href="#q5-如何修改个人信息" aria-label="Permalink to &quot;Q5: 如何修改个人信息？&quot;">​</a></h3><p><strong>A</strong>: 登录后进入个人中心，点击&quot;编辑资料&quot;，修改姓名、性别、出生日期等信息，点击&quot;保存&quot;即可。</p><p><strong>可修改的信息</strong>：</p><ul><li>姓名（firstName + lastName）</li><li>性别</li><li>出生日期</li><li>密码</li><li>邮箱（需要联系管理员） <img src="'+i+'" alt="注册页面"></li></ul><h3 id="q6-如何删除账户" tabindex="-1">Q6: 如何删除账户？ <a class="header-anchor" href="#q6-如何删除账户" aria-label="Permalink to &quot;Q6: 如何删除账户？&quot;">​</a></h3><p><strong>A</strong>: 请联系平台管理员申请删除账户。</p><p><strong>重要提示</strong>：</p><ul><li>删除后，个人信息将被永久删除</li><li>已提交的实验数据可能因研究需要保留</li><li>删除操作不可撤销，请谨慎操作</li></ul><p>联系方式：<a href="/7-technical-support/1-contact.html">技术支持</a></p><h2 id="账户安全" tabindex="-1">账户安全 <a class="header-anchor" href="#账户安全" aria-label="Permalink to &quot;账户安全&quot;">​</a></h2><h3 id="q7-如何保护账户安全" tabindex="-1">Q7: 如何保护账户安全？ <a class="header-anchor" href="#q7-如何保护账户安全" aria-label="Permalink to &quot;Q7: 如何保护账户安全？&quot;">​</a></h3><p><strong>A</strong>: 建议采取以下措施：</p><ol><li><p><strong>使用强密码</strong></p><ul><li>至少8位字符</li><li>包含大小写字母、数字和特殊字符</li><li>不要使用常见密码（如123456、password等）</li></ul></li><li><p><strong>定期更换密码</strong></p><ul><li>建议每3-6个月更换一次密码</li><li>不要在多个网站使用相同密码</li></ul></li><li><p><strong>保护邮箱安全</strong></p><ul><li>邮箱是账户恢复的重要途径</li><li>确保邮箱密码安全</li></ul></li><li><p><strong>注意登录环境</strong></p><ul><li>不要在公共电脑上保存密码</li><li>使用完毕后及时退出登录</li></ul></li><li><p><strong>警惕钓鱼邮件</strong></p><ul><li>平台不会通过邮件索要密码</li><li>注意验证邮件发送者地址</li></ul></li></ol><h3 id="q8-账号被封禁怎么办" tabindex="-1">Q8: 账号被封禁怎么办？ <a class="header-anchor" href="#q8-账号被封禁怎么办" aria-label="Permalink to &quot;Q8: 账号被封禁怎么办？&quot;">​</a></h3><p><strong>A</strong>: 如果账号被封禁，请联系管理员了解原因并申请解封。</p><p><strong>可能的封禁原因</strong>：</p><ul><li>违反平台使用规则</li><li>提交虚假信息</li><li>恶意行为（如刷数据、骚扰其他用户等）</li><li>安全风险（如账号被盗用）</li></ul><p>联系方式：<a href="/7-technical-support/1-contact.html">技术支持</a></p>',45)])])}const P=o(h,[["render",c]]);export{E as __pageData,P as default};
